defmodule MyAppWeb.ProxyController do
  use MyAppWeb, :controller

  def fetch(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, %HTTPoison.Response{status_code: status_code, body: body}} when status_code in 200..299 ->
        conn
        |> put_resp_header("content-type", "text/plain")
        |> send_resp(status_code, body)

      {:error, %HTTPoison.Error{reason: reason}} ->
        conn
        |> put_status(:bad_request)
        |> json(%{"error" => "Failed to fetch content: #{reason}"})
    end
  end

  def fetch(conn, _params) do
    conn
    |> put_status(:bad_request)
    |> json(%{"error" => "Missing 'url' parameter"})
  end
end